const customers = $input.all().map(i => i.json);
const now = new Date();

return customers.map(c => {
  const daysSince = c.last_job_date ? Math.floor((now - new Date(c.last_job_date)) / 86400000) : 999;

  // Select winback offer based on spend history
  let offer, discount;
  if ((c.total_spend || 0) >= 500) {
    offer = 'loyal_comeback';
    discount = '20% off your next service';
  } else if (daysSince < 365) {
    offer = 'seasonal_return';
    discount = '15% off + free estimate';
  } else {
    offer = 'reactivation';
    discount = '$25 off your first service back';
  }

  return { json: { ...c, days_since_last_job: daysSince, offer, discount } };
});
